44	__device__ vec4 proc_envmap(const vec3& dir, const vec3& up_dir, const vec3& sun_dir, const vec3& skycol) {
45		float skyam = dot(up_dir, dir) * 0.5f + 0.5f;
46		float sunam = std::max(0.f, dot(sun_dir, dir));
47		sunam *= sunam;
48		sunam *= sunam;
49		sunam *= sunam;
50		sunam *= sunam;
51		sunam *= sunam;
52		sunam *= sunam;
53	
54		vec4 result;
55		result.rgb() = skycol * skyam + vec3{255.f / 255.0f, 215.f / 255.0f, 195.f / 255.0f} * (20.f * sunam);
56		result.a = 1.0f;
57		return result;
58	}
59	
60	__device__ vec4 proc_envmap_render(const vec3& dir, const vec3& up_dir, const vec3& sun_dir, const vec3& skycol) {
61		// Constant background color. Uncomment the following two lines to instead render the
62		// actual sunsky model that we trained from.
63		vec4 result = vec4(0.0f);
64	
65		result = proc_envmap(dir, up_dir, sun_dir, skycol);
66	
67		return result;
68	}
