70	__device__ inline bool
71		walk_to_next_event(default_rng_t& rng, const BoundingBox& aabb, vec3& pos, const vec3& dir, const uint8_t* bitgrid, float scale) {
72		while (1) {
73			float zeta1 = random_val(rng); // sample a free flight distance and go there!
74			float dt = -std::log(1.0f - zeta1) *
75				scale; // todo - for spatially varying majorant, we must check dt against the range over which the majorant is defined. we can
76					   // turn this into an optical thickness accumulating loop...
77			pos += dir * dt;
78			if (!aabb.contains(pos)) {
79				return false; // escape to the mooon!
80			}
81			uint32_t bitidx = morton3D(int(pos.x * 128.f + 0.5f), int(pos.y * 128.f + 0.5f), int(pos.z * 128.f + 0.5f));
82			if (bitidx < 128 * 128 * 128 && bitgrid[bitidx >> 3] & (1 << (bitidx & 7))) {
83				break;
84			}
85			// loop around and try again as we are in density=0 region!
86		}
87		return true;
88	}
