90	static constexpr uint32_t MAX_TRAIN_VERTICES =
91		4; // record the first few real interactions and use as training data. uses a local array so cant be big.
92	
93	__global__ void volume_generate_training_data_kernel(
94		uint32_t n_elements,
95		vec3* pos_out,
96		vec4* target_out,
97		const void* nanovdb,
98		const uint8_t* bitgrid,
99		vec3 world2index_offset,
100		float world2index_scale,
101		BoundingBox aabb,
102		default_rng_t rng,
103		float albedo,
104		float scattering,
105		float distance_scale,
106		float global_majorant,
107		vec3 up_dir,
108		vec3 sun_dir,
109		vec3 sky_col
110	) {
111		uint32_t idx = blockIdx.x * blockDim.x + threadIdx.x;
112		if (idx >= n_elements) {
113			return;
114		}
115		rng.advance(idx * 256);
116		uint32_t numout = 0;
117		vec3 outpos[MAX_TRAIN_VERTICES];
118		float outdensity[MAX_TRAIN_VERTICES];
119		float scale = distance_scale / global_majorant;
120		const nanovdb::FloatGrid* grid = reinterpret_cast<const nanovdb::FloatGrid*>(nanovdb);
121		auto acc = grid->tree().getAccessor();
122		while (numout < MAX_TRAIN_VERTICES) {
123			uint32_t prev_numout = numout;
124			vec3 pos = random_dir(rng) * 2.0f + 0.5f;
125			vec3 target = random_val_3d(rng) * aabb.diag() + aabb.min;
126			vec3 dir = normalize(target - pos);
127			auto box_intersection = aabb.ray_intersect(pos, dir);
128			float t = max(box_intersection.x, 0.0f);
129			pos = pos + (t + 1e-6f) * dir;
130			float throughput = 1.f;
131			for (int iter = 0; iter < 128; ++iter) {
132				if (!walk_to_next_event(rng, aabb, pos, dir, bitgrid, scale)) { // escaped!
133					break;
134				}
135				vec3 nanovdbpos = pos * world2index_scale + world2index_offset;
136				float density = acc.getValue(
137					{int(nanovdbpos.x + random_val(rng)), int(nanovdbpos.y + random_val(rng)), int(nanovdbpos.z + random_val(rng))}
138				);
139	
140				if (numout < MAX_TRAIN_VERTICES) {
141					outdensity[numout] = density;
142					outpos[numout] = pos;
143					numout++;
144				}
145	
146				float extinction_prob = density / global_majorant;
147				float scatter_prob = extinction_prob * albedo;
148				float zeta2 = random_val(rng);
149				if (zeta2 >= extinction_prob) {
150					continue; // null collision
151				}
152				if (zeta2 < scatter_prob) { // was it a scatter?
153					dir = normalize(dir * scattering + random_dir(rng));
154				} else {
155					throughput = 0.f; // absorb
156					break;
157				}
158			}
159			vec4 targetcol = proc_envmap(dir, up_dir, sun_dir, sky_col) * throughput;
160			uint32_t oidx = idx * MAX_TRAIN_VERTICES;
161			for (uint32_t i = prev_numout; i < numout; ++i) {
162				float density = outdensity[i];
163				vec3 pos = outpos[i];
164				pos_out[oidx + i] = pos;
165				target_out[oidx + i] = targetcol;
166				target_out[oidx + i].w = density;
167			}
168		}
169	}
