171	void Testbed::train_volume(size_t target_batch_size, bool get_loss_scalar, cudaStream_t stream) {
172		const uint32_t n_output_dims = 4;
173		const uint32_t n_input_dims = 3;
174	
175		// Auxiliary matrices for training
176		const uint32_t batch_size = (uint32_t)target_batch_size;
177	
178		// Permute all training records to de-correlate training data
179	
180		const uint32_t n_elements = batch_size;
181		m_volume.training.positions.enlarge(n_elements);
182		m_volume.training.targets.enlarge(n_elements);
183	
184		float distance_scale = 1.f / std::max(m_volume.inv_distance_scale, 0.01f);
185		auto sky_col = m_background_color.rgb();
186	
187		linear_kernel(
188			volume_generate_training_data_kernel,
189			0,
190			stream,
191			n_elements / MAX_TRAIN_VERTICES,
192			m_volume.training.positions.data(),
193			m_volume.training.targets.data(),
194			m_volume.nanovdb_grid.data(),
195			m_volume.bitgrid.data(),
196			m_volume.world2index_offset,
197			m_volume.world2index_scale,
198			m_render_aabb,
199			m_rng,
200			m_volume.albedo,
201			m_volume.scattering,
202			distance_scale,
203			m_volume.global_majorant,
204			m_up_dir,
205			m_sun_dir,
206			sky_col
207		);
208		m_rng.advance(n_elements * 256);
209	
210		GPUMatrix<float> training_batch_matrix((float*)(m_volume.training.positions.data()), n_input_dims, batch_size);
211		GPUMatrix<float> training_target_matrix((float*)(m_volume.training.targets.data()), n_output_dims, batch_size);
212	
213		auto ctx = m_trainer->training_step(stream, training_batch_matrix, training_target_matrix);
214	
215		m_training_step++;
216	
217		if (get_loss_scalar) {
218			m_loss_scalar.update(m_trainer->loss(stream, *ctx));
219		}
220	}
