222	__global__ void init_rays_volume(
223		uint32_t sample_index,
224		vec3* __restrict__ positions,
225		Testbed::VolPayload* __restrict__ payloads,
226		uint32_t* pixel_counter,
227		ivec2 resolution,
228		vec2 focal_length,
229		mat4x3 camera_matrix,
230		vec2 screen_center,
231		Lens lens,
232		vec3 parallax_shift,
233		bool snap_to_pixel_centers,
234		BoundingBox aabb,
235		float near_distance,
236		float plane_z,
237		float aperture_size,
238		Foveation foveation,
239		Buffer2DView<const vec4> envmap,
240		vec4* __restrict__ frame_buffer,
241		float* __restrict__ depth_buffer,
242		Buffer2DView<const uint8_t> hidden_area_mask,
243		default_rng_t rng,
244		const uint8_t* bitgrid,
245		float distance_scale,
246		float global_majorant,
247		vec3 up_dir,
248		vec3 sun_dir,
249		vec3 sky_col
250	) {
251		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
252		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
253		if (x >= resolution.x || y >= resolution.y) {
254			return;
255		}
256		uint32_t idx = x + resolution.x * y;
257		rng.advance(idx << 8);
258		if (plane_z < 0) {
259			aperture_size = 0.0;
260		}
261	
262		Ray ray = pixel_to_ray(
263			sample_index,
264			{(int)x, (int)y},
265			resolution,
266			focal_length,
267			camera_matrix,
268			screen_center,
269			parallax_shift,
270			snap_to_pixel_centers,
271			near_distance,
272			plane_z,
273			aperture_size,
274			foveation,
275			hidden_area_mask,
276			lens
277		);
278	
279		if (!ray.is_valid()) {
280			depth_buffer[idx] = MAX_DEPTH();
281			return;
282		}
283	
284		ray.d = normalize(ray.d);
285		auto box_intersection = aabb.ray_intersect(ray.o, ray.d);
286		float t = max(box_intersection.x, 0.0f);
287		ray.advance(t + 1e-6f);
288		float scale = distance_scale / global_majorant;
289	
290		if (t >= box_intersection.y || !walk_to_next_event(rng, aabb, ray.o, ray.d, bitgrid, scale)) {
291			frame_buffer[idx] = proc_envmap_render(ray.d, up_dir, sun_dir, sky_col);
292			depth_buffer[idx] = MAX_DEPTH();
293		} else {
294			uint32_t dstidx = atomicAdd(pixel_counter, 1);
295			positions[dstidx] = ray.o;
296			payloads[dstidx] = {ray.d, vec4(0.f), idx};
297			depth_buffer[idx] = dot(camera_matrix[2], ray.o - camera_matrix[3]);
298		}
299	}
