376	__global__ void volume_render_kernel_step(
377		uint32_t n_pixels,
378		ivec2 resolution,
379		default_rng_t rng,
380		BoundingBox aabb,
381		const vec3* __restrict__ positions_in,
382		const Testbed::VolPayload* __restrict__ payloads_in,
383		const uint32_t* pixel_counter_in,
384		vec3* __restrict__ positions_out,
385		Testbed::VolPayload* __restrict__ payloads_out,
386		uint32_t* pixel_counter_out,
387		const vec4* network_outputs_in,
388		const vec3 up_dir,
389		const vec3 sun_dir,
390		const vec3 sky_col,
391		const void* nanovdb,
392		const uint8_t* bitgrid,
393		float global_majorant,
394		vec3 world2index_offset,
395		float world2index_scale,
396		float distance_scale,
397		float albedo,
398		float scattering,
399		vec4* __restrict__ frame_buffer,
400		bool force_finish_ray
401	) {
402		uint32_t idx = threadIdx.x + blockDim.x * blockIdx.x;
403		if (idx >= n_pixels || idx >= pixel_counter_in[0]) {
404			return;
405		}
406		Testbed::VolPayload payload = payloads_in[idx];
407		uint32_t pixidx = payload.pixidx;
408		uint32_t y = pixidx / resolution.x;
409		if (y >= resolution.y) {
410			return;
411		}
412		vec3 pos = positions_in[idx];
413		vec3 dir = payload.dir;
414		rng.advance(pixidx << 8);
415		const nanovdb::FloatGrid* grid = reinterpret_cast<const nanovdb::FloatGrid*>(nanovdb);
416		auto acc = grid->tree().getAccessor();
417		// ye olde delta tracker
418	
419		vec4 local_output = network_outputs_in[idx];
420		float scale = distance_scale / global_majorant;
421		float density = local_output.w;
422		float extinction_prob = density / global_majorant;
423		if (extinction_prob > 1.f) {
424			extinction_prob = 1.f;
425		}
426		float T = 1.f - payload.col.a;
427		float alpha = extinction_prob * T;
428		payload.col.rgb() += local_output.rgb() * alpha;
429		payload.col.a += alpha;
430		if (payload.col.a > 0.99f || !walk_to_next_event(rng, aabb, pos, dir, bitgrid, scale) || force_finish_ray) {
431			payload.col += (1.f - payload.col.a) * proc_envmap_render(dir, up_dir, sun_dir, sky_col);
432			frame_buffer[pixidx] = payload.col;
433			return;
434		}
435		uint32_t dstidx = atomicAdd(pixel_counter_out, 1);
436		positions_out[dstidx] = pos;
437		payloads_out[dstidx] = payload;
438	}
