440	void Testbed::render_volume(
441		cudaStream_t stream,
442		const CudaRenderBufferView& render_buffer,
443		const vec2& focal_length,
444		const mat4x3& camera_matrix,
445		const vec2& screen_center,
446		const Foveation& foveation,
447		const Lens& lens
448	) {
449		auto jit_guard = m_network->jit_guard(stream, true);
450	
451		float plane_z = m_slice_plane_z + m_scale;
452		float distance_scale = 1.f / std::max(m_volume.inv_distance_scale, 0.01f);
453		auto res = render_buffer.resolution;
454	
455		size_t n_pixels = (size_t)res.x * res.y;
456		for (uint32_t i = 0; i < 2; ++i) {
457			m_volume.pos[i].enlarge(n_pixels);
458			m_volume.payload[i].enlarge(n_pixels);
459		}
460		m_volume.hit_counter.enlarge(2);
461		m_volume.hit_counter.memset(0);
462	
463		vec3 sky_col = m_background_color.rgb();
464	
465		const dim3 threads = {16, 8, 1};
466		const dim3 blocks = {div_round_up((uint32_t)res.x, threads.x), div_round_up((uint32_t)res.y, threads.y), 1};
467		init_rays_volume<<<blocks, threads, 0, stream>>>(
468			render_buffer.spp,
469			m_volume.pos[0].data(),
470			m_volume.payload[0].data(),
471			m_volume.hit_counter.data(),
472			res,
473			focal_length,
474			camera_matrix,
475			screen_center,
476			lens,
477			m_parallax_shift,
478			m_snap_to_pixel_centers,
479			m_render_aabb,
480			m_render_near_distance,
481			plane_z,
482			m_aperture_size,
483			foveation,
484			m_envmap.inference_view(),
485			render_buffer.frame_buffer,
486			render_buffer.depth_buffer,
487			render_buffer.hidden_area_mask ? render_buffer.hidden_area_mask->const_view() : Buffer2DView<const uint8_t>{},
488			m_rng,
489			m_volume.bitgrid.data(),
490			distance_scale,
491			m_volume.global_majorant,
492			m_up_dir,
493			m_sun_dir,
494			sky_col
495		);
496		m_rng.advance(n_pixels * 256);
497	
498		uint32_t n = n_pixels;
499		CUDA_CHECK_THROW(cudaMemcpyAsync(&n, m_volume.hit_counter.data(), sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
500		CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
501	
502		if (m_render_ground_truth) {
503			linear_kernel(
504				volume_render_kernel_gt,
505				0,
506				stream,
507				n,
508				res,
509				m_rng,
510				m_render_aabb,
511				m_volume.pos[0].data(),
512				m_volume.payload[0].data(),
513				m_volume.hit_counter.data(),
514	
515				m_up_dir,
516				m_sun_dir,
517				sky_col,
518				m_volume.nanovdb_grid.data(),
519				m_volume.bitgrid.data(),
520				m_volume.global_majorant,
521				m_volume.world2index_offset,
522				m_volume.world2index_scale,
523				distance_scale,
524				std::min(m_volume.albedo, 0.995f),
525				m_volume.scattering,
526				render_buffer.frame_buffer
527			);
528			m_rng.advance(n_pixels * 256);
529		} else {
530			m_volume.radiance_and_density.enlarge(n);
531	
532			int max_iter = 64;
533			for (int iter = 0; iter < max_iter && n > 0; ++iter) {
534				uint32_t srcbuf = (iter & 1);
535				uint32_t dstbuf = 1 - srcbuf;
536	
537				uint32_t n_elements = next_multiple(n, BATCH_SIZE_GRANULARITY);
538				GPUMatrix<float> positions_matrix((float*)m_volume.pos[srcbuf].data(), 3, n_elements);
539				GPUMatrix<float> densities_matrix((float*)m_volume.radiance_and_density.data(), 4, n_elements);
540				m_network->inference(stream, positions_matrix, densities_matrix);
541	
542				CUDA_CHECK_THROW(cudaMemsetAsync(m_volume.hit_counter.data() + dstbuf, 0, sizeof(uint32_t), stream));
543	
544				linear_kernel(
545					volume_render_kernel_step,
546					0,
547					stream,
548					n,
549					res,
550					m_rng,
551					m_render_aabb,
552					m_volume.pos[srcbuf].data(),
553					m_volume.payload[srcbuf].data(),
554					m_volume.hit_counter.data() + srcbuf,
555					m_volume.pos[dstbuf].data(),
556					m_volume.payload[dstbuf].data(),
557					m_volume.hit_counter.data() + dstbuf,
558					m_volume.radiance_and_density.data(),
559					m_up_dir,
560					m_sun_dir,
561					sky_col,
562					m_volume.nanovdb_grid.data(),
563					m_volume.bitgrid.data(),
564					m_volume.global_majorant,
565					m_volume.world2index_offset,
566					m_volume.world2index_scale,
567					distance_scale,
568					std::min(m_volume.albedo, 0.995f),
569					m_volume.scattering,
570					render_buffer.frame_buffer,
571					(iter >= max_iter - 1)
572				);
573	
574				m_rng.advance(n_pixels * 256);
575				if (((iter + 1) % 4) == 0) {
576					// periodically tell the cpu how many pixels are left
577					CUDA_CHECK_THROW(cudaMemcpyAsync(&n, m_volume.hit_counter.data() + dstbuf, sizeof(uint32_t), cudaMemcpyDeviceToHost, stream));
578					CUDA_CHECK_THROW(cudaStreamSynchronize(stream));
579				}
580			}
581		}
582	}
583	
584	#define NANOVDB_MAGIC_NUMBER 0x304244566f6e614eUL // "NanoVDB0" in hex - little endian (uint64_t)
585	struct NanoVDBFileHeader {
586		uint64_t magic;     // 8 bytes
587		uint32_t version;   // 4 bytes version numbers
588		uint16_t gridCount; // 2 bytes
589		uint16_t codec;     // 2 bytes - must be 0
590	};
591	static_assert(sizeof(NanoVDBFileHeader) == 16, "nanovdb padding error");
592	
593	struct NanoVDBMetaData {
594		uint64_t gridSize, fileSize, nameKey, voxelCount; // 4 * 8 = 32B.
595		uint32_t gridType;                                // 4B.
596		uint32_t gridClass;                               // 4B.
597		double worldBBox[2][3];                           // 2 * 3 * 8 = 48B.
598		int indexBBox[2][3];                              // 2 * 3 * 4 = 24B.
599		double voxelSize[3];                              // 24B.
600		uint32_t nameSize;                                // 4B.
601		uint32_t nodeCount[4];                            // 4 x 4 = 16B
602		uint32_t tileCount[3];                            // 3 x 4 = 12B
603		uint16_t codec;                                   // 2B
604		uint16_t padding;                                 // 2B, due to 8B alignment from uint64_t
605		uint32_t version;                                 // 4B
606	};
607	static_assert(sizeof(NanoVDBMetaData) == 176, "nanovdb padding error");
608	
609	void Testbed::load_volume(const fs::path& data_path) {
610		if (!data_path.exists()) {
611			throw std::runtime_error{data_path.str() + " does not exist."};
612		}
613		tlog::info() << "Loading NanoVDB file from " << data_path;
614		std::ifstream f{native_string(data_path), std::ios::in | std::ios::binary};
615		NanoVDBFileHeader header;
616		NanoVDBMetaData metadata;
617		f.read(reinterpret_cast<char*>(&header), sizeof(header));
618		f.read(reinterpret_cast<char*>(&metadata), sizeof(metadata));
619	
620		if (header.magic != NANOVDB_MAGIC_NUMBER) {
621			throw std::runtime_error{"not a nanovdb file"};
622		}
623		if (header.gridCount == 0) {
624			throw std::runtime_error{"no grids in file"};
625		}
626		if (header.gridCount > 1) {
627			tlog::warning() << "Only loading first grid in file";
628		}
629		if (metadata.codec != 0) {
630			throw std::runtime_error{"cannot use compressed nvdb files"};
631		}
632		char name[256] = {};
633		if (metadata.nameSize > 256) {
634			throw std::runtime_error{"nanovdb name too long"};
635		}
636		f.read(name, metadata.nameSize);
637		tlog::info() << name << ": gridSize=" << metadata.gridSize << " filesize=" << metadata.fileSize << " voxelCount=" << metadata.voxelCount
638					 << " gridType=" << metadata.gridType << " gridClass=" << metadata.gridClass << " indexBBox=[min=["
639					 << metadata.indexBBox[0][0] << "," << metadata.indexBBox[0][1] << "," << metadata.indexBBox[0][2] << "],max]["
640					 << metadata.indexBBox[1][0] << "," << metadata.indexBBox[1][1] << "," << metadata.indexBBox[1][2] << "]]";
641	
642		std::vector<char> cpugrid;
643		cpugrid.resize(metadata.gridSize);
644		f.read(cpugrid.data(), metadata.gridSize);
645		m_volume.nanovdb_grid.enlarge(metadata.gridSize);
646		m_volume.nanovdb_grid.copy_from_host(cpugrid);
647		const nanovdb::FloatGrid* grid = reinterpret_cast<const nanovdb::FloatGrid*>(cpugrid.data());
648	
649		float mn = 10000.0f, mx = -10000.0f;
650		bool hmm = grid->hasMinMax();
651		// grid->tree().extrema(mn,mx);
652		int xsize = std::max(1, metadata.indexBBox[1][0] - metadata.indexBBox[0][0]);
653		int ysize = std::max(1, metadata.indexBBox[1][1] - metadata.indexBBox[0][1]);
654		int zsize = std::max(1, metadata.indexBBox[1][2] - metadata.indexBBox[0][2]);
655		float maxsize = std::max(std::max(xsize, ysize), zsize);
656		float scale = 1.0f / maxsize;
657		m_aabb = m_render_aabb = BoundingBox{
658			vec3{0.5f - xsize * scale * 0.5f, 0.5f - ysize * scale * 0.5f, 0.5f - zsize * scale * 0.5f},
659			vec3{0.5f + xsize * scale * 0.5f, 0.5f + ysize * scale * 0.5f, 0.5f + zsize * scale * 0.5f},
660		};
661		m_render_aabb_to_local = mat3::identity();
662	
663		m_volume.world2index_scale = maxsize;
664		m_volume.world2index_offset = vec3{
665			(metadata.indexBBox[0][0] + metadata.indexBBox[1][0]) * 0.5f - 0.5f * maxsize,
666			(metadata.indexBBox[0][1] + metadata.indexBBox[1][1]) * 0.5f - 0.5f * maxsize,
667			(metadata.indexBBox[0][2] + metadata.indexBBox[1][2]) * 0.5f - 0.5f * maxsize,
668		};
669	
670		auto acc = grid->tree().getAccessor();
671		std::vector<uint8_t> bitgrid;
672		bitgrid.resize(128 * 128 * 128 / 8);
673		for (int i = metadata.indexBBox[0][0]; i < metadata.indexBBox[1][0]; ++i) {
674			for (int j = metadata.indexBBox[0][1]; j < metadata.indexBBox[1][1]; ++j) {
675				for (int k = metadata.indexBBox[0][2]; k < metadata.indexBBox[1][2]; ++k) {
676					float d = acc.getValue({i, j, k});
677					if (d > mx) {
678						mx = d;
679					}
680					if (d < mn) {
681						mn = d;
682					}
683					if (d > 0.001f) {
684						float fx = ((i + 0.5f) - m_volume.world2index_offset.x) / m_volume.world2index_scale;
685						float fy = ((j + 0.5f) - m_volume.world2index_offset.y) / m_volume.world2index_scale;
686						float fz = ((k + 0.5f) - m_volume.world2index_offset.z) / m_volume.world2index_scale;
687						uint32_t bitidx = morton3D(int(fx * 128.0f + 0.5f), int(fy * 128.0f + 0.5f), int(fz * 128.0f + 0.5f));
688						if (bitidx < 128 * 128 * 128) {
689							bitgrid[bitidx / 8] |= 1 << (bitidx & 7);
690						}
691					}
692				}
693			}
694		}
695		m_volume.bitgrid.enlarge(bitgrid.size());
696		m_volume.bitgrid.copy_from_host(bitgrid);
697		tlog::info() << "nanovdb extrema: " << mn << " " << mx << " (" << hmm << ")";
698		;
699		m_volume.global_majorant = mx;
700	}
701	
702	} // namespace ngp
